using System;
using System.Runtime.InteropServices;
using SkiaSharp;

Console.WriteLine($"Arch: {RuntimeInformation.ProcessArchitecture}");
Console.WriteLine($"OS: {RuntimeInformation.OSDescription}");
Console.WriteLine($"SkiaSharp version: {typeof(SKBitmap).Assembly.GetName().Version}");

try
{
    using var bitmap = new SKBitmap(100, 100);
    using var canvas = new SKCanvas(bitmap);
    canvas.Clear(SKColors.Red);

    var color = bitmap.GetPixel(50, 50);
    Console.WriteLine($"GetPixel(50,50) = {color}");

    using var paint = new SKPaint();
    paint.Color = SKColors.Blue;
    canvas.DrawRect(10, 10, 80, 80, paint);

    var color2 = bitmap.GetPixel(50, 50);
    Console.WriteLine($"After DrawRect, GetPixel(50,50) = {color2}");

    using var image = SKImage.FromBitmap(bitmap);
    using var data = image.Encode(SKEncodedImageFormat.Png, 100);
    Console.WriteLine($"Encoded PNG size: {data.Size} bytes");

    Console.WriteLine("SUCCESS: All SkiaSharp P/Invoke calls completed without crash");
}
catch (Exception ex)
{
    Console.WriteLine($"EXCEPTION: {ex.GetType().Name}: {ex.Message}");
    Console.WriteLine(ex.StackTrace);
}
